export type Cell = [number, number];

const isNeighbor = ([x1, y1]: Cell, [x2, y2]: Cell): boolean =>
  Math.max(Math.abs(x1 - x2), Math.abs(y1 - y2)) === 1;

const countLiveNeighbors = (cell: Cell, cells: Cell[]): number =>
  cells.filter((other) => isNeighbor(cell, other)).length;

const isLive = ([x, y]: Cell, cells: Cell[]): boolean =>
  cells.some(([cx, cy]) => cx === x && cy === y);

const OFFSETS: ReadonlyArray<[number, number]> = [
  [-1, -1], [-1, 0], [-1, 1],
  [ 0, -1], [ 0, 0], [ 0, 1],
  [ 1, -1], [ 1, 0], [ 1, 1],
];

const candidateCells = (cells: Cell[]): Cell[] => {
  const all = cells.flatMap(([x, y]) =>
    OFFSETS.map(([dx, dy]): Cell => [x + dx, y + dy])
  );
  return Array.from(
    new Map(all.map((c) => [`${c[0]},${c[1]}`, c])).values()
  );
};

export const nextGeneration = (cells: Cell[]): Cell[] =>
  candidateCells(cells).filter((cell) => {
    const n = countLiveNeighbors(cell, cells);
    return isLive(cell, cells) ? n === 2 || n === 3 : n === 3;
  });

